class Solution {
    public int minSwaps(String s) {
        int balance = 0;
        int swaps = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == '[') {
                balance++;
            } else {
                balance--;
            }
            if (balance < 0) {
                swaps++;
                balance = 1; // Swap this ']' with a '[' ahead
            }
        }
        return swaps;
    }
}

